parsed.api_descriptions:
API_name: nchu_course_teachers_get_courses
Description:
{
  "description": "取得特定教師的課程授課紀錄。",
  "required_parameters": [
    {
      "name": "teacher_id",
      "type": "STRING",
      "description": "教師 ID（來自搜尋結果）"
    }
  ],
  "optional_parameters": [
    {
      "name": "semester",
      "type": "STRING",
      "description": "可選的學期篩選（例如：「1131」）",
      "default": null
    },
    {
      "name": "limit",
      "type": "NUMBER",
      "description": "最多回傳幾筆課程結果（預設為 50）",
      "default": 50
    }
  ]
}

